package com.socialblog.interaction.application;import com.socialblog.interaction.api.ApiException;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.repository.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service public class InteractionService{public record State(TargetType targetType,UUID targetId,long count,boolean likedByCurrentUser){}private final InteractionRepository interactions;private final TargetProjectionRepository targets;private final OutboxEventRepository outbox;private final DomainEventFactory events;public InteractionService(InteractionRepository i,TargetProjectionRepository t,OutboxEventRepository o,DomainEventFactory e){interactions=i;targets=t;outbox=o;events=e;}@Transactional public State like(UUID actor,TargetType type,UUID target){TargetProjection projection=requireTarget(type,target);if(interactions.findByActorIdAndTargetTypeAndTargetId(actor,type,target).isEmpty()){Interaction x=interactions.save(new Interaction(actor,type,target));outbox.save(events.created(x,projection.getOwnerId()));}return state(actor,type,target);}@Transactional public State unlike(UUID actor,TargetType type,UUID target){interactions.findByActorIdAndTargetTypeAndTargetId(actor,type,target).ifPresent(x->{interactions.delete(x);outbox.save(events.removed(x));});return state(actor,type,target);}@Transactional(readOnly=true)public State get(UUID actor,TargetType type,UUID target){return new State(type,target,interactions.countByTargetTypeAndTargetId(type,target),actor!=null&&interactions.findByActorIdAndTargetTypeAndTargetId(actor,type,target).isPresent());}private State state(UUID actor,TargetType type,UUID target){interactions.flush();return get(actor,type,target);}private TargetProjection requireTarget(TargetType type,UUID id){return targets.findById(new TargetKey(type,id)).filter(TargetProjection::isActive).orElseThrow(()->new ApiException(HttpStatus.CONFLICT,"TARGET_NOT_AVAILABLE","Target does not exist or is unavailable"));}}
